'use client'

import { useState } from 'react'
import { Dialog, DialogContent } from '@/components/ui/dialog'
import { Menu, X } from 'lucide-react'

interface NavigationItem {
  name: string
  href?: string
  dropdown?: { title: string; desc: string; href: string }[]
}

interface AnnouncementBanner {
  text: string
  linkText: string
  linkHref: string
}

interface CallToAction {
  text: string
  href: string
  variant: 'primary' | 'secondary'
}

interface HeroLandingProps {
  // Logo and branding
  logo?: {
    src: string
    alt: string
    companyName: string
  }
  
  // Navigation
  navigation?: NavigationItem[]
  loginText?: string
  loginHref?: string
  
  // Hero content
  title: string
  description: string
  announcementBanner?: AnnouncementBanner
  callToActions?: CallToAction[]
  
  // Styling options
  titleSize?: 'small' | 'medium' | 'large'
  gradientColors?: {
    from: string
    to: string
  }
  
  // Additional customization
  className?: string
}

const defaultProps: Partial<HeroLandingProps> = {
  logo: {
    src: "https://tailwindcss.com/plus-assets/img/logos/mark.svg?color=indigo&shade=600",
    alt: "Company Logo",
    companyName: "Your Company"
  },
  navigation: [
    { name: 'Product', href: '#' },
    { name: 'Features', href: '#' },
    { name: 'Marketplace', href: '#' },
    { name: 'Company', href: '#' },
  ],
  loginText: "Log in",
  loginHref: "#",
  titleSize: "large",
  gradientColors: {
    from: "oklch(0.646 0.222 41.116)",
    to: "oklch(0.488 0.243 264.376)"
  },
  callToActions: [
    { text: "Get started", href: "#", variant: "primary" },
    { text: "Learn more", href: "#", variant: "secondary" }
  ]
}

export function HeroLanding(props: HeroLandingProps) {
  const {
    logo,
    navigation,
    loginText,
    loginHref,
    title,
    description,
    announcementBanner,
    callToActions,
    titleSize,
    className
  } = { ...defaultProps, ...props }

  const [mobileMenuOpen, setMobileMenuOpen] = useState(false)
  const [openDropdown, setOpenDropdown] = useState<string | null>(null)

  const getTitleSizeClasses = () => {
    switch (titleSize) {
      case 'small':
        return 'text-2xl sm:text-3xl md:text-5xl'
      case 'medium':
        return 'text-2xl sm:text-4xl md:text-6xl'
      case 'large':
      default:
        return 'text-5xl sm:text-7xl lg:text-[5.5rem] leading-[1.1]'
    }
  }

  const renderCallToAction = (cta: CallToAction, index: number) => {
    if (cta.variant === 'primary') {
      return (
        <a
          key={index}
          href={cta.href}
          className="rounded-lg bg-blue-600 px-4 py-2.5 sm:px-5 sm:py-3 text-xs sm:text-sm font-semibold text-white shadow-md hover:bg-blue-700 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-600 transition-all font-sans"
        >
          {cta.text}
        </a>
      )
    } else {
      return (
        <a
          key={index}
          href={cta.href}
          className="text-xs sm:text-sm/6 font-semibold text-zinc-900 hover:text-zinc-600 transition-colors"
        >
          {cta.text} <span aria-hidden="true">→</span>
        </a>
      )
    }
  }

  return (
    <div className={`w-full overflow-hidden relative ${className || ''}`}>


      <header className="absolute inset-x-0 top-0 z-1">
        <nav aria-label="Global" className="flex items-center justify-between p-4 sm:p-6 lg:px-8">
          <div className="flex lg:flex-1">
            <a href="#" className="-m-1.5 p-1.5 flex items-center gap-1 cursor-pointer">
              <span className="sr-only">{logo?.companyName}</span>
              {logo?.src ? (
                  // eslint-disable-next-line @next/next/no-img-element
                  <img alt={logo?.alt} src={logo?.src} className="h-6 sm:h-8 w-auto" />
              ) : (
                  <div className="text-xl font-bold tracking-tight">
                    Use<span className="text-blue-600">Converra</span>
                  </div>
              )}
            </a>
          </div>
          <div className="flex lg:hidden">
            <button
              type="button"
              onClick={() => setMobileMenuOpen(true)}
              className="-m-2.5 inline-flex items-center justify-center rounded-md p-2.5 text-zinc-500 hover:text-zinc-900 transition-colors"
            >
              <span className="sr-only">Open main menu</span>
              <Menu aria-hidden="true" className="size-6" />
            </button>
          </div>
          {navigation && navigation.length > 0 && (
            <div className="hidden lg:flex lg:gap-x-8 xl:gap-x-12">
              {navigation.map((item) => (
                <div key={item.name} className="relative">
                  {item.dropdown ? (
                    <>
                      <button 
                        onClick={() => setOpenDropdown(openDropdown === item.name ? null : item.name)}
                        className="flex items-center gap-1 text-sm/6 font-semibold text-zinc-900 hover:text-zinc-500 transition-colors py-2 outline-none"
                      >
                        {item.name}
                        <svg className={`w-4 h-4 text-zinc-400 transition-transform ${openDropdown === item.name ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                        </svg>
                      </button>

                      {openDropdown === item.name && (
                        <>
                          <div className="fixed inset-0 z-40" onClick={() => setOpenDropdown(null)} />
                          <div className="absolute top-full left-0 mt-0 w-80 rounded-2xl bg-white p-4 shadow-xl ring-1 ring-zinc-200 z-50 animate-in fade-in zoom-in-95 duration-200">
                            {item.dropdown.map((drop) => (
                              <a key={drop.title} href={drop.href} onClick={() => setOpenDropdown(null)} className="block p-3 rounded-xl hover:bg-zinc-50 transition-colors relative z-50">
                                <p className="font-semibold text-zinc-900 text-sm">{drop.title}</p>
                                <p className="text-zinc-500 text-xs mt-0.5 font-medium">{drop.desc}</p>
                              </a>
                            ))}
                          </div>
                        </>
                      )}
                    </>
                  ) : (
                    <a href={item.href} className="flex items-center text-sm/6 font-semibold text-zinc-900 hover:text-zinc-500 transition-colors py-2">
                      {item.name}
                    </a>
                  )}
                </div>
              ))}
            </div>
          )}
          {loginText && loginHref && (
            <div className="hidden lg:flex lg:flex-1 lg:justify-end">
              <a href={loginHref} className="text-sm/6 font-semibold text-zinc-900 hover:text-zinc-500 transition-colors">
                {loginText} <span aria-hidden="true">&rarr;</span>
              </a>
            </div>
          )}
        </nav>
        <Dialog open={mobileMenuOpen} onOpenChange={setMobileMenuOpen}>
          <DialogContent className="fixed inset-y-0 right-0 z-50 w-full overflow-y-auto bg-white px-4 py-4 sm:px-6 sm:py-6 sm:max-w-sm sm:ring-1 sm:ring-zinc-200 lg:hidden font-sans">
            <div className="flex items-center justify-between">
              <a href="#" className="-m-1.5 p-1.5 flex items-center gap-1 cursor-pointer">
                <span className="sr-only">{logo?.companyName}</span>
                {logo?.src ? (
                    // eslint-disable-next-line @next/next/no-img-element
                    <img alt={logo?.alt} src={logo?.src} className="h-6 sm:h-8 w-auto" />
                ) : (
                    <div className="text-xl font-bold tracking-tight">
                      Use<span className="text-blue-600">Converra</span>
                    </div>
                )}
              </a>
              <button
                type="button"
                onClick={() => setMobileMenuOpen(false)}
                className="-m-2.5 rounded-md p-2.5 text-zinc-500 hover:text-zinc-900 transition-colors"
              >
                <span className="sr-only">Close menu</span>
                <X aria-hidden="true" className="size-6" />
              </button>
            </div>
            <div className="mt-2 flow-root">
              <div className="-my-6 divide-y divide-zinc-200">
                {navigation && navigation.length > 0 && (
                  <div className="space-y-2 py-6">
                    {navigation.map((item) => (
                      <div key={item.name}>
                        {item.dropdown ? (
                          <div className="space-y-1">
                            <div className="px-3 py-2 text-base/7 font-semibold text-zinc-900">
                              {item.name}
                            </div>
                            <div className="pl-6 space-y-1">
                              {item.dropdown.map(drop => (
                                <a key={drop.title} href={drop.href} className="block rounded-lg py-2 pl-3 pr-3 text-sm/6 font-medium text-zinc-600 hover:bg-zinc-50">
                                  {drop.title}
                                </a>
                              ))}
                            </div>
                          </div>
                        ) : (
                          <a
                            href={item.href}
                            className="-mx-3 block rounded-lg px-3 py-2 text-base/7 font-semibold text-zinc-900 hover:bg-zinc-50 hover:text-zinc-900 transition-colors"
                          >
                            {item.name}
                          </a>
                        )}
                      </div>
                    ))}
                  </div>
                )}
                {loginText && loginHref && (
                  <div className="py-6">
                    <a
                      href={loginHref}
                      className="-mx-3 block rounded-lg px-3 py-2.5 text-base/7 font-semibold text-zinc-900 hover:bg-zinc-50 hover:text-zinc-900 transition-colors"
                    >
                      {loginText}
                    </a>
                  </div>
                )}
              </div>
            </div>
          </DialogContent>
        </Dialog>
      </header>

      <div className="relative isolate px-6 overflow-hidden flex flex-col justify-center pt-32 pb-16 sm:pt-40 sm:pb-24">        
        <div className="mx-auto max-w-4xl">
          {/* Announcement banner */}
          {announcementBanner && (
            <div className="hidden sm:mb-2 sm:flex sm:justify-center">
              <div className="relative rounded-full px-2 py-1 text-xs sm:px-3 sm:text-sm/6 text-zinc-500 ring-1 ring-zinc-200 hover:ring-blue-600 transition-all font-sans">
                {announcementBanner.text}{' '}
                <a href={announcementBanner.linkHref} className="font-semibold text-blue-600 hover:text-blue-500 transition-colors">
                  <span aria-hidden="true" className="absolute inset-0" />
                  {announcementBanner.linkText} <span aria-hidden="true">&rarr;</span>
                </a>
              </div>
            </div>
          )}
          
          <div className="text-center">
            <h1 className={`${getTitleSizeClasses()} font-bold tracking-tighter text-balance text-zinc-900 font-sans mx-auto max-w-3xl`}>
              {title}
            </h1>
            <p className="mt-6 sm:mt-8 text-base sm:text-lg font-medium text-pretty text-zinc-500 sm:text-xl/8 font-sans">
              {description}
            </p>
            
            {/* Call to action buttons */}
            {callToActions && callToActions.length > 0 && (
              <div className="mt-8 sm:mt-10 flex items-center justify-center gap-x-4 sm:gap-x-6">
                {callToActions.map((cta, index) => renderCallToAction(cta, index))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  )
}

export type { HeroLandingProps, NavigationItem, AnnouncementBanner, CallToAction }
